const crypto = require('crypto');
const uuid = require('uuid');

function generateToken() {
  return new Promise((resolve, reject) => {
    const tokenLength = 64;
    const chars = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';
    let token = '';

    for (let i = 0; i < tokenLength; i++) {
      token += chars[Math.floor(Math.random() * chars.length)];
    }

    resolve(token);
  });
}

function generateIdToken(email, expirationDate) {
  return new Promise((resolve, reject) => {
    const id = uuid.v4();
    const encodedData = Buffer.from(`${email}:${expirationDate}`).toString('base64');
    const hash = crypto.createHash('sha256').update(id).digest('hex');

    resolve({ id, token: `${encodedData}:${hash}` });
  });
}

function generatePasswordResetLink(email, expirationDate) {
  return new Promise((resolve, reject) => {
    generateIdToken(email, expirationDate)
      .then((result) => {
        const passwordResetUrl = `https://example.com/reset-password/${result.token}`;
        resolve(passwordResetUrl);
      })
      .catch((error) => {
        reject(error);
      });
  });
}

